import * as path from "path";

import * as AasJsonization from "../src/jsonization";

import * as TestCommon from "./common";

function readExpectedJson(
    classJsonName: string,
    fileName: "minimal.json" | "maximal.json"
): AasJsonization.JsonValue {
  const pth = path.join(TestCommon.TEST_DATA_DIR, "Json", "Expected", classJsonName, fileName);
  return TestCommon.readJsonFromFileSync(pth);
}

function mustBeJsonObject(jsonable: AasJsonization.JsonValue): AasJsonization.JsonObject {
  if (
    typeof jsonable !== "object" ||
    jsonable === null ||
    typeof jsonable[Symbol.iterator] === "function"
  ) {
    throw new Error(`Expected a JSON object, but got: ${JSON.stringify(jsonable)}`);
  }

  return <AasJsonization.JsonObject>jsonable;
}

test("Extension deserialization fails on non-object", () => {
  const jsonable = "This is not a JSON object.";

  const instanceOrError = AasJsonization.extensionFromJsonable(
    jsonable
  );

  expect(instanceOrError.error).not.toBeNull();
});

test("Extension deserialization fails with missing required property", () => {
  const jsonable = readExpectedJson(
    "Extension",
    "minimal.json"
  );

  const jsonObject = { ...mustBeJsonObject(jsonable) };
  delete jsonObject["name"];

  const instanceOrError = AasJsonization.extensionFromJsonable(
    jsonObject
  );

  expect(instanceOrError.error).not.toBeNull();
});

test("Extension deserialization fails with property type mismatch", () => {
  const jsonable = readExpectedJson(
    "Extension",
    "maximal.json"
  );

  const jsonObject = { ...mustBeJsonObject(jsonable) };
  jsonObject["supplementalSemanticIds"] = { definitely: "unexpected-object" };

  const instanceOrError = AasJsonization.extensionFromJsonable(
    jsonObject
  );

  expect(instanceOrError.error).not.toBeNull();
});

test("OperationVariable deserialization fails with invalid nested modelType", () => {
  const jsonable = readExpectedJson(
    "OperationVariable",
    "maximal.json"
  );

  const jsonObject = { ...mustBeJsonObject(jsonable) };
  const nestedValue = jsonObject["value"];

  if (
    typeof nestedValue !== "object" ||
    nestedValue === null ||
    typeof nestedValue[Symbol.iterator] === "function"
  ) {
    throw new Error("Expected nested class JSON object to be present in maximal example.");
  }

  const nestedObject = { ...<AasJsonization.JsonObject>nestedValue };
  nestedObject["modelType"] = "DefinitelyNotAModelType";
  jsonObject["value"] = nestedObject;

  const instanceOrError = AasJsonization.operationVariableFromJsonable(
    jsonObject
  );

  expect(instanceOrError.error).not.toBeNull();
});

